import * as React from 'react';
import { raf } from '@rc-component/util';

type Updater<ValueType> = (prev?: ValueType) => ValueType;

export default function useFrameState<ValueType>(
  defaultValue: ValueType,
): [ValueType, (updater: Updater<ValueType>) => void] {
  const [value, setValue] = React.useState(defaultValue);
  const frameRef = React.useRef<number | null>(null);
  const batchRef = React.useRef<Updater<ValueType>[]>([]);
  const destroyRef = React.useRef(false);

  React.useEffect(() => {
    destroyRef.current = false;
    return () => {
      destroyRef.current = true;
      raf.cancel(frameRef.current!);
      frameRef.current = null;
    };
  }, []);

  function setFrameValue(updater: Updater<ValueType>) {
    if (destroyRef.current) {
      return;
    }

    if (frameRef.current === null) {
      batchRef.current = [];
      frameRef.current = raf(() => {
        frameRef.current = null;
        setValue((prevValue) => {
          let current = prevValue;

          batchRef.current.forEach((func) => {
            current = func(current);
          });

          return current;
        });
      });
    }

    batchRef.current.push(updater);
  }

  return [value, setFrameValue];
}

import type { CatalogConfig } from './types'
import { styleText } from 'node:util'
import prompts from '@posva/prompts'

const SKIP = '__skip__'
const CREATE_NEW = '__create_new__'

export interface CatalogSelection {
  catalogName: string | undefined
}

export async function promptSelectCatalog(
  config: CatalogConfig,
  pkgName: string,
  programmatic?: boolean,
): Promise<CatalogSelection> {
  // Only default catalog: no prompt needed
  if (config.hasDefaultCatalog && !config.hasNamedCatalogs) {
    return { catalogName: 'default' }
  }

  if (programmatic) {
    return { catalogName: undefined }
  }

  const catalogChoices = config.catalogs.map(c => ({
    title: c.name,
    value: c.name,
  }))

  const { catalog } = await prompts({
    type: 'select',
    name: 'catalog',
    message: `select catalog for ${styleText('yellow', pkgName)}`,
    choices: [
      ...catalogChoices,
      { title: styleText('dim', 'create new catalog'), value: CREATE_NEW },
      { title: styleText('dim', 'skip (install without catalog)'), value: SKIP },
    ],
  })

  if (catalog === undefined || catalog === SKIP) {
    return { catalogName: undefined }
  }

  if (catalog === CREATE_NEW) {
    const newName = await promptNewCatalogName()
    return { catalogName: newName }
  }

  return { catalogName: catalog }
}

async function promptNewCatalogName(): Promise<string | undefined> {
  const { name } = await prompts({
    type: 'text',
    name: 'name',
    message: 'new catalog name',
  })
  return name || undefined
}

import type { ResolvedDepChange } from '../types'
import { DependenciesTypeShortMap } from '../types'
import { DiffMap } from './diff'
import { toDate } from './time'

export type SortKey = 'time' | 'diff' | 'name'
export type SortOrder = 'asc' | 'desc'

export type SortOption = `${SortKey}-${SortOrder}`
export const SORT_CHOICES = [
  'time-asc',
  'time-desc',
  'diff-asc',
  'diff-desc',
  'name-asc',
  'name-desc',
] as const

export function parseSortOption(option: SortOption) {
  return option.split('-') as [SortKey, SortOrder]
}

export function sortDepChanges(
  changes: readonly ResolvedDepChange[],
  option: SortOption,
  grouped: boolean,
): ResolvedDepChange[] {
  const [sortKey, order = 'asc'] = parseSortOption(option)

  let sorted = changes.concat()
    .sort((a, b) => {
      if (sortKey === 'time') {
        if (a.targetVersionTime && b.targetVersionTime) {
          const at = toDate(a.targetVersionTime)
          const bt = toDate(b.targetVersionTime)
          return bt - at
        }
      }
      else if (sortKey === 'name') {
        return a.name.localeCompare(b.name)
      }
      else if (sortKey === 'diff') {
        return DiffMap[a.diff || ''] - DiffMap[b.diff || '']
      }
      return 0
    })

  sorted = order === 'desc'
    ? sorted.reverse()
    : sorted

  if (grouped) {
    const order = Object.keys(DependenciesTypeShortMap)
    sorted = sorted.sort((a, b) => {
      const ai = order.indexOf(a.source)
      const bi = order.indexOf(b.source)
      return ai - bi
    })
  }

  return sorted
}

interface PromiseWithResolvers<T> {
  promise: Promise<T>;
  resolve: (value: T | PromiseLike<T>) => void;
  reject: (reason?: any) => void;
}

function withResolvers<T>(): PromiseWithResolvers<T> {
  const rv = {} as PromiseWithResolvers<T>;
  rv.promise = new Promise<T>((resolve, reject) => {
    rv.resolve = resolve;
    rv.reject = reject;
  });
  return rv;
}

function promiseTry<T>(fn: () => Promise<T>): Promise<T> {
  return new Promise<T>((resolve) => resolve(fn()));
}

export function createPromiseQueue(concurrency: number) {
  const jobs: Array<{
    fn: () => Promise<unknown>;
    resolve: PromiseWithResolvers<unknown>["resolve"];
    reject: PromiseWithResolvers<unknown>["reject"];
  }> = [];

  let active = 0;

  function run() {
    if (active >= concurrency) {
      return;
    }

    const job = jobs.shift();

    if (!job) {
      return;
    }

    active++;

    promiseTry(job.fn).then(
      (result) => {
        active--;
        job.resolve(result);
        run();
      },
      (error) => {
        active--;
        job.reject(error);
        run();
      }
    );
  }

  return {
    add: <T>(fn: () => Promise<T>): Promise<T> => {
      const { promise, resolve, reject } = withResolvers();
      jobs.push({
        fn,
        resolve,
        reject,
      });
      run();
      return promise as Promise<T>;
    },
    setConcurrency: (newConcurrency: number) => {
      concurrency = newConcurrency;
      run();
    },
  };
}

