import { errors, StringUtils, SyntaxKind } from "@ts-morph/common";
import { Node } from "../../compiler";
import { InsertionTextManipulator } from "./InsertionTextManipulator";

export class UnwrapTextManipulator extends InsertionTextManipulator {
  constructor(node: Node) {
    super({
      insertPos: node.getStart(true),
      newText: getReplacementText(node),
      replacingLength: node.getWidth(true),
    });
  }
}

function getReplacementText(node: Node) {
  const sourceFile = node._sourceFile;
  const range = getInnerBraceRange();
  const startPos = range[0];
  const text = sourceFile.getFullText().substring(range[0], range[1]);

  return StringUtils.indent(text, -1, {
    indentText: sourceFile._context.manipulationSettings.getIndentationText(),
    indentSizeInSpaces: sourceFile._context.manipulationSettings._getIndentSizeInSpaces(),
    isInStringAtPos: pos => sourceFile.isInStringAtPos(startPos + pos),
  }).trim();

  function getInnerBraceRange() {
    const bodyNode = getBodyNodeOrThrow();
    return [bodyNode.getStart() + 1, bodyNode.getEnd() - 1] as const;

    function getBodyNodeOrThrow() {
      if (Node.isModuleDeclaration(node)) {
        const bodyNode = node._getInnerBody();
        if (bodyNode == null)
          throw new errors.InvalidOperationError("This operation requires the module to have a body.");
        return bodyNode;
      } else if (Node.isBodied(node))
        return node.getBody();
      else if (Node.isBodyable(node))
        return node.getBodyOrThrow();
      else
        errors.throwNotImplementedForSyntaxKindError(node.getKind(), node);
    }
  }
}

import path from 'node:path'
import { type TreeshakingOptions, type TreeshakingPreset, rollup } from 'rollup'
import type { Plugin } from '../plugin'

export type TreeshakingStrategy =
  | boolean
  | TreeshakingOptions
  | TreeshakingPreset

export const treeShakingPlugin = ({
  treeshake,
  name,
  silent,
}: {
  treeshake?: TreeshakingStrategy
  name?: string
  silent?: boolean
}): Plugin => {
  return {
    name: 'tree-shaking',

    async renderChunk(code, info) {
      if (!treeshake || !/\.(cjs|js|mjs)$/.test(info.path)) return

      const bundle = await rollup({
        input: [info.path],
        plugins: [
          {
            name: 'tsup',
            resolveId(source) {
              if (source === info.path) return source
              return false
            },
            load(id) {
              if (id === info.path) return { code, map: info.map }
            },
          },
        ],
        treeshake,
        makeAbsoluteExternalsRelative: false,
        preserveEntrySignatures: 'exports-only',
        onwarn: silent ? () => {} : undefined,
      })

      const result = await bundle.generate({
        interop: 'auto',
        format: this.format,
        file: info.path,
        sourcemap: !!this.options.sourcemap,
        compact: !!this.options.minify,
        name,
      })

      for (const file of result.output) {
        if (
          file.type === 'chunk' &&
          file.fileName === path.basename(info.path)
        ) {
          return {
            code: file.code,
            map: file.map,
          }
        }
      }
    },
  }
}

import { Octokit } from "@octokit/rest";
import parseGitUrl from "git-url-parse";
import log from "../../npmlog";
import { ValidationError } from "../../validation-error";

const childProcess = require("@lerna/child-process");

export function createGitHubClient(): Octokit {
  // TODO: refactor based on TS feedback
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  log.silly("createGitHubClient");

  const { GH_TOKEN, GHE_API_URL, GHE_VERSION } = process.env;

  if (!GH_TOKEN) {
    throw new ValidationError(
      "",
      `A GH_TOKEN environment variable is required when "createRelease" is set to "github"`
    );
  }

  if (GHE_VERSION) {
    Octokit.plugin(require(`@octokit/plugin-enterprise-rest/ghe-${GHE_VERSION}`));
  }

  const options = {
    auth: `token ${GH_TOKEN}`,
  };

  if (GHE_API_URL) {
    // TODO: refactor based on TS feedback
    // eslint-disable-next-line @typescript-eslint/ban-ts-comment
    // @ts-ignore
    options.baseUrl = GHE_API_URL;
  }

  return new Octokit(options);
}

export function parseGitRepo(remote = "origin", opts?: any) {
  // TODO: refactor based on TS feedback
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  log.silly("parseGitRepo");

  const args = ["config", "--get", `remote.${remote}.url`];

  // TODO: refactor based on TS feedback
  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
  // @ts-ignore
  log.verbose("git", args);

  const url = childProcess.execSync("git", args, opts);

  if (!url) {
    throw new ValidationError("", `Git remote URL could not be found using "${remote}".`);
  }

  return parseGitUrl(url);
}

