import {
    codeFixAll,
    createCodeFixActionWithoutFixAll,
    registerCodeFix,
    setJsonCompilerOptionValue,
} from "../_namespaces/ts.codefix.js";
import {
    Diagnostics,
    factory,
    textChanges,
    TsConfigSourceFile,
} from "../_namespaces/ts.js";

const fixID = "fixEnableJsxFlag";
const errorCodes = [Diagnostics.Cannot_use_JSX_unless_the_jsx_flag_is_provided.code];
registerCodeFix({
    errorCodes,
    getCodeActions: function getCodeActionsToFixEnableJsxFlag(context) {
        const { configFile } = context.program.getCompilerOptions();
        if (configFile === undefined) {
            return undefined;
        }

        const changes = textChanges.ChangeTracker.with(context, changeTracker => doChange(changeTracker, configFile));
        return [
            createCodeFixActionWithoutFixAll(fixID, changes, Diagnostics.Enable_the_jsx_flag_in_your_configuration_file),
        ];
    },
    fixIds: [fixID],
    getAllCodeActions: context =>
        codeFixAll(context, errorCodes, changes => {
            const { configFile } = context.program.getCompilerOptions();
            if (configFile === undefined) {
                return undefined;
            }

            doChange(changes, configFile);
        }),
});

function doChange(changeTracker: textChanges.ChangeTracker, configFile: TsConfigSourceFile) {
    setJsonCompilerOptionValue(changeTracker, configFile, "jsx", factory.createStringLiteral("react"));
}

import type { Tree } from '@nx/devkit';
import { updateJson } from '@nx/devkit';
import { getInstalledAngularVersionInfo } from '../../utils/version-utils';
import type { NormalizedSchema } from './normalized-schema';

export function enableStrictTypeChecking(
  host: Tree,
  options: NormalizedSchema
): void {
  // This matches the settings defined by the Angular CLI https://angular.io/guide/strict-mode
  const compilerOptions = {
    strict: true,
    noImplicitOverride: true,
    noPropertyAccessFromIndexSignature: true,
    noImplicitReturns: true,
    noFallthroughCasesInSwitch: true,
  };

  const appTsConfigPath = `${options.appProjectRoot}/tsconfig.json`;
  if (host.exists(appTsConfigPath)) {
    const { major: angularMajorVersion } = getInstalledAngularVersionInfo(host);

    updateJson(host, appTsConfigPath, (json) => {
      json.compilerOptions = { ...json.compilerOptions, ...compilerOptions };
      json.angularCompilerOptions = {
        ...json.angularCompilerOptions,
        strictInjectionParameters: true,
        strictInputAccessModifiers: true,
        typeCheckHostBindings: angularMajorVersion === 20 ? true : undefined,
        strictTemplates: true,
      };
      return json;
    });
  }

  const e2eTsConfigPath = `${options.e2eProjectRoot}/tsconfig.json`;
  if (host.exists(e2eTsConfigPath)) {
    updateJson(host, e2eTsConfigPath, (json) => {
      json.compilerOptions = { ...json.compilerOptions, ...compilerOptions };
      return json;
    });
  }
}

"use client-entry";

import type { ReactNode } from 'react';
import {hydrate, fetchRSC} from '@parcel/rsc/client';

let updateRoot = hydrate({
  // Intercept HMR window reloads, and do it with RSC instead.
  onHmrReload() {
    navigate(location.pathname);
  }
});

// A very simple router. When we navigate, we'll fetch a new RSC payload,
// and in a React transition, stream in the new page. Once complete, we'll
// pushState to update the URL in the browser.
async function navigate(pathname: string, push = false) {
  let root = await fetchRSC<ReactNode>(pathname.replace(/\.html$/, '.rsc'));
  updateRoot(root, () => {
    if (push) {
      history.pushState(null, '', pathname);
    }
  });
}

// Intercept link clicks to perform RSC navigation.
document.addEventListener('click', e => {
  let link = (e.target as Element).closest('a');
  if (
    link &&
    link instanceof HTMLAnchorElement &&
    link.href &&
    (!link.target || link.target === '_self') &&
    link.origin === location.origin &&
    !link.hasAttribute('download') &&
    e.button === 0 && // left clicks only
    !e.metaKey && // open in new tab (mac)
    !e.ctrlKey && // open in new tab (windows)
    !e.altKey && // download
    !e.shiftKey &&
    !e.defaultPrevented
  ) {
    e.preventDefault();
    navigate(link.pathname, true);
  }
});

// When the user clicks the back button, navigate with RSC.
window.addEventListener('popstate', e => {
  navigate(location.pathname);
});

import * as dp from '@pnpm/deps.path'
import { PnpmError } from '@pnpm/error'
import type { PatchGroup, PatchGroupRecord, PatchInfo } from '@pnpm/patching.types'
import { validRange } from 'semver'

export function groupPatchedDependencies (patchedDependencies: Record<string, string | PatchInfo>): PatchGroupRecord {
  const result: PatchGroupRecord = {}
  function getGroup (name: string): PatchGroup {
    let group: PatchGroup | undefined = result[name]
    if (group) return group
    group = {
      exact: {},
      range: [],
      all: undefined,
    }
    result[name] = group
    return group
  }

  for (const key in patchedDependencies) {
    const value = patchedDependencies[key]
    const info = typeof value === 'string' ? { hash: value } : value
    const { name, version, nonSemverVersion } = dp.parse(key)

    if (name && version) {
      getGroup(name).exact[version] = { ...info, key }
      continue
    }

    if (name && nonSemverVersion) {
      if (!validRange(nonSemverVersion)) {
        throw new PnpmError('PATCH_NON_SEMVER_RANGE', `${nonSemverVersion} is not a valid semantic version range.`)
      }
      if (nonSemverVersion.trim() === '*') {
        getGroup(name).all = { ...info, key }
      } else {
        getGroup(name).range.push({
          version: nonSemverVersion,
          patch: { ...info, key },
        })
      }
      continue
    }

    getGroup(key).all = { ...info, key }
  }

  return result
}

import { inspect } from 'node:util';
import { writeSync } from 'node:fs';
import {
	options, bgBlue, black, bgLightYellow, bgGray,
} from 'kolorist';

export const debugEnabled = Number(process.env.TSX_DEBUG);

// Force colors in debug mode
if (debugEnabled) {
	options.enabled = true;
	options.supportLevel = 3;
}

const createLog = (
	name: string,
) => (
	level: number,
	...args: any[]
) => {
	if (!debugEnabled) {
		return;
	}

	if (level > debugEnabled) {
		return;
	}

	const prefix = `${bgGray(` tsx P${process.pid} `)} ${name}`;
	const logMessage = args.map(argumentElement => (
		typeof argumentElement === 'string'
			? argumentElement
			: inspect(argumentElement, { colors: true })
	)).join(' ');

	writeSync(
		1,
		`${prefix} ${logMessage}\n`,
	);
};

export const logCjs = createLog(bgLightYellow(black(' CJS ')));
export const logEsm = createLog(bgBlue(' ESM '));

export const time = <T extends (...args: any[]) => unknown>(
	name: string,
	_function: T,
	threshold = 100,
): T => function (
		this: unknown,
		...args: Parameters<T>
	) {
		const timeStart = Date.now();
		const logTimeElapsed = () => {
			const elapsed = Date.now() - timeStart;

			if (elapsed > threshold) {
				console.log(name, {
					args,
					elapsed,
				});
			}
		};

