const interpolate = (string: string, data: Record<string, string> = {}) =>
  Object.entries(data).reduce((acc, [k, v]) => acc.replace(new RegExp(`%${k}%`, 'g'), v), string);

export function getPreviewBodyTemplate(
  configDirPath: string,
  interpolations?: Record<string, string>
) {
  const base = readFileSync(
    join(resolvePackageDir('storybook'), 'assets/server/base-preview-body.html'),
    'utf8'
  );

  const bodyHtmlPath = resolve(configDirPath, 'preview-body.html');
  let result = base;

  if (existsSync(bodyHtmlPath)) {
    result = readFileSync(bodyHtmlPath, 'utf8') + result;
  }

  return interpolate(result, interpolations);
}

export function getPreviewHeadTemplate(
  configDirPath: string,
  interpolations?: Record<string, string>
) {
  const base = readFileSync(
    join(resolvePackageDir('storybook'), 'assets/server/base-preview-head.html'),
    'utf8'
  );
  const headHtmlPath = resolve(configDirPath, 'preview-head.html');

  let result = base;

  if (existsSync(headHtmlPath)) {
    result += readFileSync(headHtmlPath, 'utf8');
  }

  return interpolate(result, interpolations);
}

import { TRPCError } from '../error/TRPCError';
import { isObject } from '../utils';
import type { TRPCRequestInfo } from './types';

export function parseConnectionParamsFromUnknown(
  parsed: unknown,
): TRPCRequestInfo['connectionParams'] {
  try {
    if (parsed === null) {
      return null;
    }
    if (!isObject(parsed)) {
      throw new Error('Expected object');
    }
    const nonStringValues = Object.entries(parsed).filter(
      ([_key, value]) => typeof value !== 'string',
    );

    if (nonStringValues.length > 0) {
      throw new Error(
        `Expected connectionParams to be string values. Got ${nonStringValues
          .map(([key, value]) => `${key}: ${typeof value}`)
          .join(', ')}`,
      );
    }
    return parsed as Record<string, string>;
  } catch (cause) {
    throw new TRPCError({
      code: 'PARSE_ERROR',
      message: 'Invalid connection params shape',
      cause,
    });
  }
}
export function parseConnectionParamsFromString(
  str: string,
): TRPCRequestInfo['connectionParams'] {
  let parsed: unknown;
  try {
    parsed = JSON.parse(str);
  } catch (cause) {
    throw new TRPCError({
      code: 'PARSE_ERROR',
      message: 'Not JSON-parsable query params',
      cause,
    });
  }
  return parseConnectionParamsFromUnknown(parsed);
}

import type { TSESTree } from '@typescript-eslint/utils';

import { AST_NODE_TYPES } from '@typescript-eslint/utils';

export function isAssignee(node: TSESTree.Node): boolean {
  const parent = node.parent;
  if (!parent) {
    return false;
  }

  // a[i] = 1, a[i] += 1, etc.
  if (
    parent.type === AST_NODE_TYPES.AssignmentExpression &&
    parent.left === node
  ) {
    return true;
  }

  // delete a[i]
  if (
    parent.type === AST_NODE_TYPES.UnaryExpression &&
    parent.operator === 'delete' &&
    parent.argument === node
  ) {
    return true;
  }

  // a[i]++, --a[i], etc.
  if (
    parent.type === AST_NODE_TYPES.UpdateExpression &&
    parent.argument === node
  ) {
    return true;
  }

  // [a[i]] = [0]
  if (parent.type === AST_NODE_TYPES.ArrayPattern) {
    return true;
  }

  // [...a[i]] = [0]
  if (parent.type === AST_NODE_TYPES.RestElement) {
    return true;
  }

  // ({ foo: a[i] }) = { foo: 0 }
  if (
    parent.type === AST_NODE_TYPES.Property &&
    parent.value === node &&
    parent.parent.type === AST_NODE_TYPES.ObjectExpression &&
    isAssignee(parent.parent)
  ) {
    return true;
  }

  // (a[i] as number)++, [...a[i]!] = [0], etc.
  if (
    (parent.type === AST_NODE_TYPES.TSNonNullExpression ||
      parent.type === AST_NODE_TYPES.TSAsExpression ||
      parent.type === AST_NODE_TYPES.TSTypeAssertion ||
      parent.type === AST_NODE_TYPES.TSSatisfiesExpression) &&
    isAssignee(parent)
  ) {
    return true;
  }

  return false;
}

